import React, { useEffect, useMemo, useState } from 'react'
import { taskService, pondService, productService, userService } from '../../services/api'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
]

const normalize = (v) => String(v || '').toUpperCase()

const formatDateTime = (v) => {
  if (!v) return '-'
  const d = new Date(v)
  return Number.isNaN(d.getTime()) ? v : d.toLocaleString('vi-VN')
}

const TechnicianTasks = () => {
  const { user } = useAuth()

  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])

  const [loading, setLoading] = useState(true)

  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')

  const [isCreateOpen, setIsCreateOpen] = useState(false)
  const [selectedTask, setSelectedTask] = useState(null)

  const [form, setForm] = useState({
    task_type: '',
    pond_id: '',
    description: '',
    due_date: '',
    product_id: '',
    quantity: 1,
    assigned_workers: [],
  })

  // ================= FETCH =================
  const fetchAll = async () => {
    try {
      setLoading(true)

      const [t, p, pr, w] = await Promise.all([
        taskService.getAllTasks(),
        pondService.getAllPonds(),
        productService.getAllProducts(),
        userService.getWorkers(),
      ])

      setTasks(t?.data?.data || [])
      setPonds(p?.data?.data || [])
      setProducts(pr?.data?.data || [])
      setWorkers(w?.data?.data || [])
    } catch (err) {
      showToast({ title: 'Không tải dữ liệu', type: 'error' })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchAll()
  }, [])

  // ================= FILTER =================
  const filteredTasks = useMemo(() => {
    const s = search.toLowerCase()

    return tasks.filter(t => {
      const matchSearch =
        !s ||
        t.task_title?.toLowerCase().includes(s) ||
        t.pond_name?.toLowerCase().includes(s)

      const matchStatus =
        statusFilter === 'ALL' ||
        normalize(t.status) === statusFilter

      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  // ================= DERIVED =================
  const filteredPonds = useMemo(() => {
    if (!form.task_type) return ponds

    if (['FEEDING', 'TREATMENT', 'HARVEST'].includes(form.task_type)) {
      return ponds.filter(p => p.status === 'DANG_NUOI')
    }

    if (form.task_type === 'POND_PROCESS') {
      return ponds.filter(p => p.status === 'DANG_CAI_TAO')
    }

    return ponds
  }, [ponds, form.task_type])

  const filteredProducts = useMemo(() => {
    if (!form.task_type) return []

    switch (form.task_type) {
      case 'FEEDING':
        return products.filter(p => p.type === 'FEED')
      case 'TREATMENT':
        return products.filter(p => p.type === 'MEDICINE')
      case 'POND_PROCESS':
        return products.filter(p => p.type === 'CHEMICAL')
      default:
        return []
    }
  }, [products, form.task_type])

  // ================= HANDLERS =================
  const toggleWorker = (id) => {
    setForm(prev => {
      const exists = prev.assigned_workers.includes(id)

      return {
        ...prev,
        assigned_workers: exists
          ? prev.assigned_workers.filter(i => i !== id)
          : [...prev.assigned_workers, id],
      }
    })
  }

  const handleCreate = async () => {
    try {
      await taskService.createTask(form)
      showToast({ title: 'Tạo công việc thành công', type: 'success' })

      setIsCreateOpen(false)
      setForm({
        task_type: '',
        pond_id: '',
        description: '',
        due_date: '',
        product_id: '',
        quantity: 1,
        assigned_workers: [],
      })

      fetchAll()
    } catch {
      showToast({ title: 'Tạo công việc thất bại', type: 'error' })
    }
  }

  const handleStatusChange = async (id, status) => {
    try {
      await taskService.updateTaskStatus(id, status)
      showToast({ title: 'Cập nhật thành công', type: 'success' })
      fetchAll()
    } catch {
      showToast({ title: 'Cập nhật thất bại', type: 'error' })
    }
  }

  // ================= UI =================
  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="spinner" />
      </div>
    )
  }

  return (
    <div className="dashboard admin-page technician-tasks">

      {/* HEADER */}
      <div className="table-header">
        <div>
          <h2>Công việc kỹ thuật</h2>
          <p>Phân công & theo dõi</p>
        </div>

        <button onClick={() => setIsCreateOpen(true)}>
          + Tạo công việc
        </button>
      </div>

      {/* FILTER */}
      <div className="table-toolbar">
        <input
          placeholder="Tìm công việc / ao..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          {STATUS_OPTIONS.map(o => (
            <option key={o.value} value={o.value}>{o.label}</option>
          ))}
        </select>
      </div>

      {/* TABLE */}
      <table className="table-base">
        <thead>
          <tr>
            <th>Công việc</th>
            <th>Ao</th>
            <th>Hạn</th>
            <th>Trạng thái</th>
          </tr>
        </thead>

        <tbody>
          {filteredTasks.map(t => (
            <tr key={t.task_id}>
              <td>{t.task_title}</td>
              <td>{t.pond_name}</td>
              <td>{formatDateTime(t.due_date)}</td>

              <td>
                <select
                  value={t.status}
                  onChange={(e) => handleStatusChange(t.task_id, e.target.value)}
                >
                  <option value="PENDING">Chờ</option>
                  <option value="IN_PROGRESS">Đang làm</option>
                  <option value="COMPLETED">Xong</option>
                </select>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* CREATE MODAL */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>

            <h3>Tạo công việc</h3>

            {/* TYPE */}
            <select
              value={form.task_type}
              onChange={(e) =>
                setForm({ ...form, task_type: e.target.value, pond_id: '', product_id: '' })
              }
            >
              <option value="">Loại công việc</option>
              <option value="FEEDING">Cho ăn</option>
              <option value="TREATMENT">Cho thuốc</option>
              <option value="HARVEST">Thu hoạch</option>
              <option value="POND_PROCESS">Xử lý ao</option>
            </select>

            {/* POND */}
            <select
              value={form.pond_id}
              onChange={(e) => setForm({ ...form, pond_id: e.target.value })}
            >
              <option value="">Chọn ao</option>
              {filteredPonds.map(p => (
                <option key={p.pond_id} value={p.pond_id}>
                  {p.pond_name}
                </option>
              ))}
            </select>

            {/* PRODUCT */}
            {filteredProducts.length > 0 && (
              <>
                <select
                  value={form.product_id}
                  onChange={(e) => setForm({ ...form, product_id: e.target.value })}
                >
                  <option value="">Chọn sản phẩm</option>
                  {filteredProducts.map(p => (
                    <option key={p.product_id} value={p.product_id}>
                      {p.product_name}
                    </option>
                  ))}
                </select>

                <input
                  type="number"
                  min={1}
                  value={form.quantity}
                  onChange={(e) => setForm({ ...form, quantity: Number(e.target.value) })}
                  placeholder="Số lượng"
                />
              </>
            )}

            {/* WORKERS TABLE */}
            <div className="worker-grid">
              {workers.map(w => (
                <label key={w.user_id}>
                  <input
                    type="checkbox"
                    checked={form.assigned_workers.includes(w.user_id)}
                    onChange={() => toggleWorker(w.user_id)}
                  />
                  {w.full_name}
                </label>
              ))}
            </div>

            <div className="modal-actions">
              <button onClick={() => setIsCreateOpen(false)}>Hủy</button>
              <button onClick={handleCreate}>Tạo</button>
            </div>

          </div>
        </div>
      )}
    </div>
  )
}

export default TechnicianTasks
